SELECT A.APPLY_NO, A.PERSON_ID, A.OT_TYPE_CODE, GET_GLOBAL_NAME(A.OT_TYPE_CODE, #{lang, jdbcType=VARCHAR}) AS OT_TYPE_NAME, TO_CHAR(A.APPLY_OT_DATE, 'DD/MM/YYYY') AS APPLY_OT_DATE, A.OT_FROM_TIME, A.OT_TO_TIME, A.OT_APPLY_HOUR, A.DEDUCT_YN, A.APPLY_OT_REMARK, A.AFFIRM_FLAG, GET_GLOBAL_NAME(A.AFFIRM_FLAG, #{lang, jdbcType=VARCHAR}) AS AFFIRM_FLAG_NAME, A.CONFIRM_FLAG, GET_GLOBAL_NAME(TO_CHAR(A.CONFIRM_FLAG), #{lang, jdbcType=VARCHAR}) AS CONFIRM_FLAG_NAME, A.CREATED_BY, A.CREATED_IP FROM ESS_APPLY_OT A WHERE A.PERSON_ID = #{adminID, jdbcType=VARCHAR} AND A.ACTIVITY = 1
AND A.OT_TYPE_CODE = #{otTypeCodeSearch, jdbcType=VARCHAR}
AND A.AFFIRM_FLAG = #{affirmFlagSearch, jdbcType=VARCHAR}
AND A.APPLY_OT_DATE >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND A.APPLY_OT_DATE < TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD') + 1
ORDER BY A.APPLY_OT_DATE DESC, A.CREATE_DATE DESC

SELECT ( SELECT COUNT(1) FROM AR_DETAIL_HTSV D JOIN ESS_APPLY_OT ESS ON ESS.PERSON_ID = D.PERSON_ID WHERE ESS.APPLY_NO IN
#{no, jdbcType=VARCHAR}
AND TO_CHAR(ESS.OT_FROM_TIME, 'YYYY/MM/DD') = D.AR_DATE_STR AND D.LOCK_YN = 'Y' ) + ( SELECT COUNT(1) FROM AR_DEPARTMENT_MANAGE AD JOIN HR_EMPLOYEE HE ON HE.DEPTNO = AD.DEPT_NO JOIN ESS_APPLY_OT ESS ON ESS.PERSON_ID = HE.PERSON_ID WHERE ESS.APPLY_NO IN
#{no, jdbcType=VARCHAR}
AND TO_CHAR(ESS.OT_FROM_TIME, 'YYYY-MM-DD') = AD.LOCK_DATE AND (AD.LOCK_OT_FLAG = '1' OR AD.LOCK_OT_NIGHT_FLAG = '1') ) AS LOCKED_COUNT FROM DUAL

